var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"세상엔 소원을 이뤄주는 일곱 요정이 있다고 해요.","JPN":"この世には願いを叶えてくれる七人の妖精がいるそうです。","ENG":"People say there are seven fairies that grant wishes.","TWN":"聽說世界上有七個可以替人完成願望的精靈。"},"stage":{"bg":"EV_SIGMA_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"요정들은 가장 위대한 사람들 곁에 머물며, 소원을 하나씩 이뤄줬대요.","JPN":"彼らは最も偉大な人間の元に訪れ、願いを1つずつ叶えてくれたとか。","ENG":"These fairies reside by the greatest people and grant their wishes one by one.","TWN":"精靈會停留在最偉大的人身邊，為他一一實現願望。"},"stage":{"bg":"EV_SIGMA_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"사람들은 요정이 옛날 이야기일 뿐이라 하지만…","JPN":"人々は妖精なんかおとぎ話の存在でしかないと言いますが……","ENG":"People say that fairies are all old folktales, but...","TWN":"大家都認為精靈只是神話故事…"},"stage":{"bg":"EV_SIGMA_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"전 요정이 아직 어딘가에 있다고 믿고 싶어요.","JPN":"私は妖精がまだどこかに存在していると信じたいのです。","ENG":"I want to believe that fairies are still out there somewhere.","TWN":"但我相信，精靈一定就在世界的某個地方。"},"stage":{"bg":"EV_SIGMA_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"저도 요정님에게 위대한 사람으로 인정받아서… 꼭 빌고 싶은 소원이 있거든요.","JPN":"私も妖精さんから偉大な人間として認められて……ぜひ叶えてもらいたい願いがあるんです。","ENG":"Because I want to be recognized as one of the greatest... and have my wish come true.","TWN":"我也要成為偉大的人，得到精靈的認可。因為…我有必須實現的願望。"},"stage":{"bg":"EV_SIGMA_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"먹을 거 사왔어요. 엄마.","JPN":"食べ物を買ってきたよ、お母さん。","ENG":"I brought food, Mommy.","TWN":"媽媽，我買吃的回來了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"고생했구나.","JPN":"あら、ご苦労様。","ENG":"You did a good job.","TWN":"辛苦你了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"이번엔 달걀도 사온 거니?","JPN":"今日もタマゴを買ってきたのかしら？","ENG":"Did you buy eggs this time?","TWN":"你有買雞蛋嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"네! 엄마가 해주는 오믈렛. 세상에서 제일 좋아하니까요.","JPN":"うん！　お母さんのオムレツが世界で一番美味しいから。","ENG":"Yup! Because the omelets you make are my favorite thing in the world.","TWN":"當然有！我最喜歡媽媽做的歐姆蛋了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"후후… 우리 딸 생일인데, 원한다면 당연히 해줘야지.","JPN":"ふふ……あなたの誕生日なんだし、もちろん作るわよ。","ENG":"Haha... Since it's your birthday, of course, I should make what you like the most.","TWN":"呵呵…我的乖女兒生日，想吃什麼媽媽當然要做給你吃囉。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"오는 길에 눈에 띄지는 않았고?","JPN":"それと、家に帰ってくるとき、誰かに見られたりしなかった？","ENG":"Did anyone notice you while you were out?","TWN":"回來的路上沒有被人發現吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"응, 늘 같이 다니던 골목으로 갔더니 아무한테도 안 들켰어요.","JPN":"うん、いつもの路地裏を通ってきたから、誰にも見つかっていないよ。","ENG":"Nope. I wasn't seen by anyone because I used the alley we always use.","TWN":"沒有，我走同一條路回來的，沒有被人發現。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"근데, 다녀오는 길에 제 또래의 아이들을 봤어요.","JPN":"でも、途中で私と同じぐらいの子どもたちがいて","ENG":"But I saw some kids my age on my way back.","TWN":"不果我回來的時候，有看到幾個和我同年紀的小孩。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"순례단의 용사들 놀이를 하고 있는데, 재밌어 보이더라고요.","JPN":"巡礼団の勇者ごっこをしていて、すごく楽しそうだった。","ENG":"They were playing as pilgrim heroes, and it looked fun.","TWN":"他們假扮成朝聖團的勇士在玩，感覺好好玩。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"금발의 여자애가 에클레시아님 역할을 맡았는데… 목검 하나로 엄청 멋지게 마왕을 물리쳤어요!","JPN":"そこにいた金髪の女の子がエクレシア様のマネをしていて、木刀で魔王を倒すところがすごくかっこよかったの！","ENG":"The blonde-haired girl played the role of Miss Ecclesia... and she defeated the Demon Lord with just one wooden sword!","TWN":"金頭髮的小女生扮成艾可露西亞…拿著一把木劍劈向魔王，超帥的！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"하마터면 박수를 칠 뻔했다니까요?","JPN":"思わず拍手しそうになったけど、我慢したよ。","ENG":"I almost started clapping when I saw that.","TWN":"我還差一點要鼓掌叫好欸？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"그 애들이… 너에게 말을 걸었니?","JPN":"その子たちに……声をかけられたの？","ENG":"Those kids... did they talk to you?","TWN":"他們…有跟你說話嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"음… 아뇨.","JPN":"うーん……かけられてない。","ENG":"Um... no.","TWN":"嗯…沒有。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"잠깐 구경만 하다가 왔어요.","JPN":"私が一方的に見ていただけ。","ENG":"I just watched them for a bit then left.","TWN":"我在旁邊看一下就走了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"제가 있는 줄도 몰랐을 거예요.","JPN":"私のことなんて気づいていなかったと思うわ。","ENG":"I'm sure they didn't even know I was looking.","TWN":"他們應該沒發覺我的存在。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"그래… 잘 했구나.","JPN":"そう……わかったわ。","ENG":"Okay... You did good.","TWN":"是嗎…那就好。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"그런데 엄마.","JPN":"ところでお母さん。","ENG":"But Mommy?","TWN":"媽媽，"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"우리 언제까지 이렇게 숨어 지내야 해요?","JPN":"いったいいつまで私たちは隠れながら暮らさないといけないの？","ENG":"How much longer do we have to stay hidden?","TWN":"我們要這樣躲到什麼時候？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"우리가 숨어 살아야 할 정도로 나쁜 죄를 지었나요?","JPN":"人目についちゃいけないほど、重罪を犯したの？","ENG":"Did we do something so bad that we have to live in hiding?","TWN":"我們做了什麼十惡不赦的壞事，所以才必須這樣躲躲藏藏的嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"미안하구나, 아가.","JPN":"本当にごめんね。","ENG":"I'm sorry, my child.","TWN":"媽媽對不起你。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"이렇게 된 건…","JPN":"こうなったのは……","ENG":"It's all my fault...","TWN":"都怪媽媽不好…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"전부 내 잘못이야.","JPN":"全部私のせいなの。","ENG":"that we're living like this.","TWN":"害你必須過這種日子。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"그런 말 마요. 엄마는 아무 잘못 없어요.","JPN":"そんなこと言わないで、お母さんは何も悪くない。","ENG":"Don't say that. You did nothing wrong, Mommy.","TWN":"媽媽你別這麼說，這不是媽媽的錯。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"엄마는 세상에서 제일 좋은 사람이니까요. 제가 알아요.","JPN":"お母さんは世界で一番優しい人だよ。私が一番よくわかっている。","ENG":"You're the nicest person in the world. I know you are.","TWN":"我知道媽媽是全世界最善良的人。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"우리 착한 딸…","JPN":"あなたは優しい子ね……","ENG":"My precious daughter...","TWN":"我的乖女兒…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"네 꿈이 뭐라고 했지?","JPN":"もう一度、あなたの夢を聞かせてくれる？","ENG":"What did you say your dream was again?","TWN":"你說你的夢想是什麼？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"제 꿈은…","JPN":"私の夢……","ENG":"My dream is...","TWN":"我的願望是…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"에클레시아 추기경님처럼 모두에게 존경받는 사람이 되는 거요.","JPN":"エクレシア枢機卿のように、皆から尊敬を集める人物になること。","ENG":"to become someone who is respected by everyone, like Cardinal Ecclesia.","TWN":"成為艾可露西亞樞機主教一樣受人尊敬的人。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"엘리시온의 모두에게 믿음을 얻어서, 엄마랑 좀 더 떳떳하게 지내고 싶어요.","JPN":"エリシオンのみんなから信頼されて、お母さんともっと堂々と生きていきたい。","ENG":"I want to gain the trust of everyone in Elysion, so you and I can be proud, Mommy.","TWN":"我想得到艾利森所有人的信任，和媽媽一起堂堂正正地生活。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"그래. 멋진 꿈이구나.","JPN":"そうだったわね、素敵な夢よ。","ENG":"Yes. That's such a wonderful dream.","TWN":"好棒的夢想呢。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"네가 그런 위대한 사람이 된다면… 나도 무척 자랑스러울 거야.","JPN":"あなたがそうなってくれたら……私はとても誇らしいと思うわ。","ENG":"If you become such a great person... I'll also be so proud of you.","TWN":"要是你可以成為這麼棒的人…媽媽也會很驕傲的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"헤헤…","JPN":"へへ……","ENG":"Hehe...","TWN":"嘿嘿…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"콜록. 콜록.","JPN":"ゲホッ！　ゲホッ……！","ENG":"*Cough* *Cough*","TWN":"咳咳，咳咳。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"엄마…? 괜찮아요?","JPN":"お母さん……？　大丈夫？","ENG":"Mommy...? Are you all right?","TWN":"媽媽…？你還好嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"얼굴색이 많이 안 좋아요. 제가 의사 선생님을 모셔올게요.","JPN":"顔色が悪いよ。お医者さんを呼んでくるね。","ENG":"You don't look so good. I'll go get the doctor.","TWN":"你的臉色很不好，我去找醫生來。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"그건 안돼…!","JPN":"ダメよ……！","ENG":"NO...!","TWN":"不可以…！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"말했잖니. 그랬다간 너까지 위험해지고 말 거라고.","JPN":"言ったでしょ。そんなことをしたら、あなたの立場まで危うくなってしまうって。","ENG":"I've already told you. You'll also be in danger if you do that.","TWN":"媽媽不是說過，不可以讓你因此暴露在危險之中。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"하지만…","JPN":"でも……","ENG":"But...","TWN":"可是…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"역병은… 성왕님도, 요정님도 고치지 못해.","JPN":"疫病は……聖王様でも、妖精さんでも治せないわ。","ENG":"The plague... Not even the pope or a fairy can cure it.","TWN":"瘟疫…是連聖皇或精靈也沒辦法治好的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"그럴 수가…","JPN":"そんな……","ENG":"That can't be true...","TWN":"怎麼會…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"이런 지하에서 나랑 살면… 넌 영영 네 꿈을 이루지 못할 거야.","JPN":"このまま、こんな地下で私と暮らしていては……あなたの夢は永遠に叶わない。","ENG":"And if you keep living with me underground like this... you'll never be able to achieve your dreams.","TWN":"你和媽媽一起住在地下室裡…是永遠無法實現夢想的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"언젠간 네 스스로 모든 난관을 해쳐나가야 할 날이 올 거란다.","JPN":"いつかあなたは自分の力で、すべての困難を乗り越えていかなければならなくなる日が来る。","ENG":"One day, you'll have to overcome hardships on your own.","TWN":"但總有一天，你會自己突破所有難關的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"그런 말 하지 마요. 꿈 같은 거 안 이뤄도 되니까.","JPN":"そんなことを言わないで。夢なんかどうでもいいの。","ENG":"Don't say that. I don't need to achieve my dreams.","TWN":"媽媽你不要說這種話，我才不需要實現夢想。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"엄마 없이는… 혼자 버틸 자신이 없어요.","JPN":"お母さんなしでは……一人なんて耐えられない。","ENG":"And without you... I don't think I'll be able to make it on my own, Mommy.","TWN":"要是失去媽媽…我沒有信心能夠撐下去。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"괜찮아, 아가.","JPN":"大丈夫よ。","ENG":"It's all right, my child.","TWN":"沒事的，女兒。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"어젯밤, 요정님이 꿈에서 나에게 말씀하셨거든.","JPN":"昨夜、妖精さんが夢に出てきてお話ししてくれたの。","ENG":"Last night, a fairy came into my dreams and said this to me.","TWN":"昨天晚上精靈到我的夢裡來，"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"우리와 다르게… 너에겐 빛이 있다고 했어.","JPN":"普通の人とは違い……あなたには光があるって。","ENG":"\\"Unlike me... there is light within you.","TWN":"精靈說，你和我不一樣…你是屬光的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"아무리 절망적인 상황에서도… 모든 걸 이겨낼 빛이.","JPN":"どんなに絶望的な状況になっても……すべてに打ち勝てる光が。","ENG":"No matter how tough it gets... your light will overcome it all.\\"","TWN":"無論在什麼樣的絕境當中…光都能戰勝一切。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"세계는 종말을 향해 다가가고 있다.","JPN":"世界は終末に向かいつつある。","ENG":"The end of the world is nigh.","TWN":"世界正邁向滅亡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"우리가 잠들어 있을 때에도.","JPN":"我々が眠りについる間にも。","ENG":"Even when we are in slumber.","TWN":"在我們沉睡時，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"삶과 죽음의 순환을 통해 지식을 쌓고, 망각을 거듭할 때에도.","JPN":"生と死を繰り返し、知を蓄え、忘却を重ねる間にも。","ENG":"Or accrue knowledge through the cycle of life and death, and forget.","TWN":"在生與死的循環之間累積知識，又反覆遺忘時，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"세계는 역병이라는 이름의 차디찬 어둠에 천천히 물들어가고 있었다.","JPN":"世界は疫病という救いようのない暗闇によって徐々に覆い尽くされようとしていた。","ENG":"The cold darkness known as the plague slowly eats away at the world.","TWN":"世界正漸漸沒入名叫瘟疫的冰冷黑暗之中。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"옛 왕국 아발론의 드높은 위상은 영원한 겨울 속에 파묻히고, 인류는 머물 곳을 잃었다.","JPN":"かつての王国アバロンの栄華は、終わりのない冬の中に葬られ、人類は拠り所を失ってしまった。","ENG":"The old kingdom of Avalon and its glory have been buried in eternal winter, and humanity has lost its place.","TWN":"舊王國阿瓦隆的崇高地位被掩埋在永恆的冬天裡，人類失去棲身之所。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"수많은 실향민들이 희망과 안식에 들 자리를 찾아 오랜 세월 동토를 떠돌았고.","JPN":"膨大な数の難民たちは希望と安息の地を求め、長きにわたり凍土を彷徨っていた。","ENG":"Countless refugees are wandering the gelid lands for eons in search of hope and shelter.","TWN":"無數的難民為尋找希望和安身之處，長久以來在冰封的大地上四處遊走。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"그루터기에 터를 잡은 우리도 그중 하나였다.","JPN":"切り株を見つけ、そこを住処とした我々もその一部であった。","ENG":"We, who have settled in the Stump, were one of them.","TWN":"包括在木墩扎根的我們也是其中之一。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_QM","text":{"KOREA":"무슨 일이야? 마차가 아까부터 안 움직이잖아.","JPN":"いったいなんなの？　馬車がさっきから一歩も進まないじゃない。","ENG":"What's going on? Why did the carriage stop?","TWN":"怎麼回事？馬車從剛才就一直沒在前進。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_SNOW"},{"id":"L43_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"죄송합니다, 모르가나 아가씨. 바퀴가 진창에 빠진 채 굳었어요.","JPN":"申し訳ございません。モルガナお嬢様。車輪が沼にはまってしまい、抜けなくなってしまいまして。","ENG":"My apologies, Miss Morgana. But a wheel seems to be stuck in the mud.","TWN":"很抱歉，莫甘娜小姐。車輪陷入泥濘中動彈不得。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"정말 시간 아깝게.","JPN":"どれだけ時間をかけているのよ。","ENG":"What a waste of time.","TWN":"真是浪費時間。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"비켜. 내가 꺼낼 테니까.","JPN":"どきなさい、あたしが出してあげるから。","ENG":"Move. I'll pull it out from there.","TWN":"讓開，我來把車輪拉出來吧。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"다치지 않게 조심하세요.","JPN":"お怪我のないように気を付けてください。","ENG":"Be careful not to hurt yourself.","TWN":"小心別弄傷自己。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"쓸데없는 걱정이야.","JPN":"余計な心配ね。","ENG":"Stop your worrying.","TWN":"不勞你費心。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"으그그그그…!","JPN":"ぐぬぬぬぬ……！","ENG":"Errrrgh...!","TWN":"嚇呃呃呃…！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_WOOD"},{"id":"L1_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"으랴압!","JPN":"おりゃあ！","ENG":"Rrrragh!","TWN":"嘿咻！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_10"},{"id":"L5_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"앗…","JPN":"あっ……","ENG":"Ah...","TWN":"哎呀……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"이런. 바퀴가 힘을 못 이기고 부서졌군요.","JPN":"あっ、車輪が力に負けて壊れてしまったようですね。","ENG":"Oh, my. The wheel couldn't withstand the force and broke.","TWN":"糟糕，車輪被我硬拉拉壞了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"미, 미안.","JPN":"ご、ごめん。","ENG":"S-sorry about that.","TWN":"對，對不起。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"쉽진 않겠지만, 지금부터는 걸어가야겠어요.","JPN":"少し大変ですが、この先は歩くしかありませんね。","ENG":"This won't be easy, but we will have to walk from here.","TWN":"那只好辛苦點用走的了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"안돼! 괜히 무리하다 누가 얼어 죽으면 어쩌려고!","JPN":"嫌よ！　そんな無茶をして凍死したらどうするのよ？","ENG":"No! What if one of us freezes to death?!","TWN":"不行！要是勉強用走的，萬一路上有人凍死的話怎麼辦！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"그럼 당장 그루터기로 돌아갈까요?","JPN":"では切り株に戻りますか？","ENG":"Then, shall we head back to the Stump?","TWN":"那還是我們先回去木墩嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그… 그렇다고 빈손으로 가면 멀린이 실망할 거 아냐!","JPN":"で……でも、何の収穫もなしに帰ったら、マーリンにがっかりされてしまうでしょ！","ENG":"B-but Merlin will be disappointed that we returned empty-handed!","TWN":"可是…空手而歸的話，梅林會失望的！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"쳇…","JPN":"ちっ……","ENG":"Tch...","TWN":"嘖…"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"어쩔 수 없지. 저 앞에 보이는 폐허만 살펴보고 돌아가자.","JPN":"しょうがないね。目の前にみえる廃墟だけでも探索してから帰りましょう。","ENG":"Oh, well. Let's check those ruins over there and head back.","TWN":"這樣吧，我們查看那前面的廢墟後就回去。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"언제나 까칠하시군요.","JPN":"相変わらずとげとげしいお方ですね。","ENG":"Well, at least her attitude hasn't changed.","TWN":"一如往常的惡劣呢。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"태도는 저래도 부지런히 성장하고 있다는 게 중요한 거지.","JPN":"態度はあんなでも、着実に成長しているところに目を向けるとしよう。","ENG":"Regardless of her attitude, what's important is her steady growth.","TWN":"雖然她態度惡劣，但重點是她一直很努力在成長。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"멀린 제사장님이 아니었으면, 저렇게 강한 분이 저희 같은 사람들을 돕진 않았겠죠?","JPN":"マーリン司祭長がいなかったら、あれほど力のあるお方が私たちのような者に力を貸すはずがないでしょうね？","ENG":"If it weren't for High Priest Merlin, someone as strong as her wouldn't be helping us, right?","TWN":"要不是梅林祭司長，像她這麼厲害的人才不會幫我們吧？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"아가씨가 제사장님의 가르침에 영향을 받은 건 사실이지.","JPN":"お嬢様が司祭長から強く影響を受けているのは事実ではある。","ENG":"It is true that Miss Morgana is influenced by High Priest Merlin's teachings.","TWN":"小姐確實是受到祭司長教導的影響。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"하지만 우리 조사단에 지원한 건 아가씨 스스로의 의지였다네.","JPN":"だが、我々調査団に志願したのは、他でもなくお嬢様自身の意志だそうだ。","ENG":"However, it was on her own accord that she joined the survey corps.","TWN":"不過，加入調查團是她自己的意思。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"그렇게 된 지가 벌써 1년이 지났군요.","JPN":"それも、もう一年も前のことですね。","ENG":"And it has already been a year since then.","TWN":"時間過得真快，她加入也快一年了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"솔직히, 금방 싫증을 내며 관두실 줄 알았는데… 이젠 아가씨가 없는 조사단은 상상도 못 하겠어요.","JPN":"正直なところ、お嬢様ならすぐにここでの活動に嫌気がさして、お辞めになるかと思っていましたが……もうすっかり馴染んで、ここでは当たり前の存在になりましたよね。","ENG":"Honestly, I thought she'd get bored of it and quit... But now, I can't imagine the survey corps without her.","TWN":"老實說，我本來以為她待不久的…但我現在已經無法想像調查團沒有她會怎麼樣。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"참 감사한 일 아니겠나.","JPN":"ありがたいことじゃないか。","ENG":"And grateful, we must be.","TWN":"這真的很感恩不是嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"마을에 둘뿐인 성자가 우릴 위해 노력해준다는 게 말이야.","JPN":"町に二人しかいない聖者が我々の活動にご協力くださっているんだからな。","ENG":"One of the two Helgons in this village is working tirelessly for us.","TWN":"村子裡唯二的聖者在為我們努力。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"휴우, 그래도 여긴 쓸만한 적철이 많아서 다행이네.","JPN":"ふう、ここだと上質な赤鉄がたくさん手に入りそうね。","ENG":"Whew, at least there are a lot of Violarite we can use here.","TWN":"呼，還好這裡很多不錯的赤鐵。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그쪽은 어때?","JPN":"そっちはどう？","ENG":"How's it looking on your side?","TWN":"那邊情況如何？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"저희도 챙길 수 있는 적철은 모두 챙겼습니다.","JPN":"こちらも持てるだけの赤鉄を収拾できました。","ENG":"We've also collected all the Violarite we could.","TWN":"我們也把所有能拿的赤鐵都帶上了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"곳간에서 열매 종자가 담긴 바구니도 발견했어요.","JPN":"貯蔵庫から果実の種が入ったかごも見つけました。","ENG":"I've also found a basket with some fruit seeds inside the barn.","TWN":"還在倉庫裡發現一籃種子。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"정말?","JPN":"本当に？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"어떤 건데? 과일 씨앗이야?","JPN":"どんな種が入っていたの？　果物の種？","ENG":"What are they? Are they really fruit seeds?","TWN":"是什麼種子？水果的種子嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"글쎄요. 아가씨가 좋아하는 달콤한 과일이면 좋겠네요.","JPN":"どうですかね。お嬢様の好きな甘い果物の種だといいですね。","ENG":"I'm not sure. But I hope they are sweet fruits that you will like.","TWN":"不確定，但希望是小姐喜歡的水果種子。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"크흠… 좋아. 전부 마차에 싣고 얼른 돌아가자…","JPN":"コホン……まあいいわ。では馬車に積んだらすぐに帰りましょう。","ENG":"Ahem... All right. Let's put everything in the carriage and head back–","TWN":"咳嗯…好，把東西都裝上馬車後趕緊回去吧…"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…가 아니라 전부 짊어지고 가야 되지.","JPN":"……じゃなくて、全部手で持って帰らなければいけないんだったわね。","ENG":"I mean, carry them home.","TWN":"……不對，我們必須自己扛回去。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"아가씨는 쉬세요. 짐은 저희끼리 들어도 충분합니다.","JPN":"私たちが持ちますので、お嬢様は持たなくて結構ですよ。","ENG":"Miss Morgana, get some rest. We'll carry it instead.","TWN":"小姐休息吧，行李就交給我們來扛。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"됐어. 나만 빈손으로 가면 멀린이 또 잔소리할 거라고.","JPN":"大丈夫よ。あたしだけ何も持っていなかったら、マーリンにまた怒られちゃうから。","ENG":"No. Merlin's going to nag me if I return empty-handed.","TWN":"不行，只有我二手空空的話，梅林一定會唸我的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"무거운 건 다 나한테…","JPN":"重いものは全部あたしに……","ENG":"So give me all the heavy stuff–","TWN":"重的東西都交給我…"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이건… 마물의 포효소리?","JPN":"これは……魔物の鳴き声？","ENG":"Was that... a monster's roar?","TWN":"這是…怪物的咆哮聲？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"건너편 농가 쪽입니다!","JPN":"あっちの農家です！","ENG":"It's coming from the farm on the other side!","TWN":"從對面農舍傳來的！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"이런…! 키안 영감님이 거길 살펴보러 갔는데!","JPN":"まずいぞ……！　キアンのじいさんがあの辺りを探索している！","ENG":"Damit...! Kian was over there!","TWN":"糟糕…奇恩大叔還在那裡！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"할아범이…?","JPN":"おじいちゃんが……？","ENG":"Kian...?","TWN":"奇恩爺爺…？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"너희들 먼저 그루터기로 돌아가!","JPN":"あなたたち、先に切り株に戻って！","ENG":"All of you, head back to the Stump!","TWN":"你們幾個先回去木墩！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"네? 하지만…","JPN":"えっ？　しかし……","ENG":"What? But...","TWN":"什麼？可是…"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭘 하지만이야! 마물들이 더 꼬였다간 다 같이 못 빠져나간다고!","JPN":"早く！　魔物がこれ以上集まってきたら、全員殺られちゃうわよ！","ENG":"Just go! If more monsters appear, we won't all make it out!","TWN":"可是什麼！萬一有更多怪物跑過來，到時候我們一個都跑不掉！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"할아범은 내가 데려갈 테니, 얼른 떠나!","JPN":"おじいちゃんはあたしがなんとか連れて帰るから、あなたたちは先に行って！","ENG":"I'll go get Kian, so go!","TWN":"我會負責把奇恩爺爺帶回去，你們快走！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"아, 알겠습니다! 조심하세요!","JPN":"わ、わかりました！　どうかお気をつけてください！","ENG":"O-okay! Be careful!","TWN":"好，知道了！小姐小心！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"긴장하지 말고 정신 차려, 모르가나.","JPN":"緊張してる場合じゃない、しっかりしなきゃ、モルガナ。","ENG":"Don't stiffen up and focus, Morgana.","TWN":"莫甘娜，保持冷靜，集中精神。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"넌 성자잖아. 넌 해낼 수 있어.","JPN":"あなたは聖者よ。できるに決まってる。","ENG":"You're a Helgon. You can do it.","TWN":"你是聖者，你可以的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그러기 위해 태어난 거니까.","JPN":"そのために生まれてきたんだから。","ENG":"You were born for this.","TWN":"你是為此而生的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"}]`);export{e as default};